# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

// ==================== Constants ====================
object PrefsConstants {
    const val PREFS_NAME = "auth_prefs"
    const val KEY_AUTHENTICATED = "is_authenticated"
    const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
    const val KEY_SAVED_PASSWORD = "saved_password"
    const val KEY_USERNAME = "saved_username"
    const val DEFAULT_PASSWORD = "password123"
    const val DEFAULT_USERNAME = "user"
}

// ==================== AuthManager ====================
class AuthManager(context: Context) {

    private val prefs: SharedPreferences =
        context.getSharedPreferences(PrefsConstants.PREFS_NAME, Context.MODE_PRIVATE)

    var isAuthenticated: Boolean
        get() = prefs.getBoolean(PrefsConstants.KEY_AUTHENTICATED, false)
        set(value) {
            prefs.edit().putBoolean(PrefsConstants.KEY_AUTHENTICATED, value).apply()
        }

    var isBiometricEnabled: Boolean
        get() = prefs.getBoolean(PrefsConstants.KEY_BIOMETRIC_ENABLED, false)
        set(value) {
            prefs.edit().putBoolean(PrefsConstants.KEY_BIOMETRIC_ENABLED, value).apply()
        }

    var savedPassword: String
        get() = prefs.getString(PrefsConstants.KEY_SAVED_PASSWORD, PrefsConstants.DEFAULT_PASSWORD) ?: PrefsConstants.DEFAULT_PASSWORD
        set(value) {
            prefs.edit().putString(PrefsConstants.KEY_SAVED_PASSWORD, value).apply()
        }

    var savedUsername: String
        get() = prefs.getString(PrefsConstants.KEY_USERNAME, PrefsConstants.DEFAULT_USERNAME) ?: PrefsConstants.DEFAULT_USERNAME
        set(value) {
            prefs.edit().putString(PrefsConstants.KEY_USERNAME, value).apply()
        }

    fun validateCredentials(username: String, password: String): Boolean {
        return username == savedUsername && password == savedPassword
    }

    fun logout() {
        isAuthenticated = false
    }

    fun clearAll() {
        prefs.edit().clear().apply()
    }
}

// ==================== BiometricHelper ====================
class BiometricHelper(private val activity: AppCompatActivity) {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private val executor: Executor = ContextCompat.getMainExecutor(activity)

    fun isBiometricAvailable(): BiometricAvailability {
        val biometricManager = BiometricManager.from(activity)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> BiometricAvailability.AVAILABLE
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> BiometricAvailability.NO_HARDWARE
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> BiometricAvailability.HARDWARE_UNAVAILABLE
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> BiometricAvailability.NOT_ENROLLED
            else -> BiometricAvailability.UNKNOWN_ERROR
        }
    }

    fun authenticate(
        title: String = "Biometric Authentication",
        subtitle: String = "Use your fingerprint to log in",
        negativeButtonText: String = "Use Password Instead",
        onSuccess: () -> Unit,
        onError: (errorCode: Int, errorMessage: String) -> Unit,
        onFailed: () -> Unit
    ) {
        biometricPrompt = BiometricPrompt(activity, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    onSuccess()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    onError(errorCode, errString.toString())
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    onFailed()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(title)
            .setSubtitle(subtitle)
            .setNegativeButtonText(negativeButtonText)
            .setConfirmationRequired(false)
            .build()

        biometricPrompt.authenticate(promptInfo)
    }

    enum class BiometricAvailability {
        AVAILABLE,
        NO_HARDWARE,
        HARDWARE_UNAVAILABLE,
        NOT_ENROLLED,
        UNKNOWN_ERROR
    }
}

// ==================== SplashActivity ====================
class SplashActivity : AppCompatActivity() {

    private lateinit var authManager: AuthManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authManager = AuthManager(this)

        if (authManager.isAuthenticated) {
            navigateToMain()
        } else {
            navigateToLogin()
        }
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }

    private fun navigateToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

