class LoginActivity : AppCompatActivity() {

    private lateinit var authManager: AuthManager
    private lateinit var biometricHelper: BiometricHelper

    private lateinit var etUsername: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnLogin: Button
    private lateinit var btnBiometric: Button
    private lateinit var tvStatus: TextView
    private lateinit var tvTitle: TextView
    private lateinit var tvSubtitle: TextView

    private var failedBiometricAttempts = 0
    private val maxBiometricFailures = 3

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(getLoginLayoutResourceId())

        authManager = AuthManager(this)
        biometricHelper = BiometricHelper(this)

        initViews()
        setupBiometricButton()
        setupLoginButton()

        // Auto-prompt biometric if available and previously enabled
        if (authManager.isBiometricEnabled) {
            promptBiometricIfAvailable()
        }
    }

    private fun getLoginLayoutResourceId(): Int {
        // In a real app, this would be R.layout.activity_login
        // For demonstration, we create the layout programmatically
        return createLoginLayoutProgrammatically()
    }

    private fun createLoginLayoutProgrammatically(): Int {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            gravity = android.view.Gravity.CENTER
            setPadding(64, 64, 64, 64)
        }

        tvTitle = TextView(this).apply {
            text = "Welcome Back"
            textSize = 28f
            setTypeface(null, android.graphics.Typeface.BOLD)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvTitle, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 16 })

        tvSubtitle = TextView(this).apply {
            text = "Please sign in to continue"
            textSize = 14f
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvSubtitle, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 64 })

        etUsername = EditText(this).apply {
            hint = "Username"
            inputType = android.text.InputType.TYPE_CLASS_TEXT
            setPadding(28, 28, 28, 28)
        }
        layout.addView(etUsername, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 24 })

        etPassword = EditText(this).apply {
            hint = "Password"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
            setPadding(28, 28, 28, 28)
        }
        layout.addView(etPassword, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 48 })

        btnLogin = Button(this).apply {
            text = "Sign In"
        }
        layout.addView(btnLogin, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 32 })

        btnBiometric = Button(this).apply {
            text = "Use Fingerprint"
        }
        layout.addView(btnBiometric, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 32 })

        tvStatus = TextView(this).apply {
            textSize = 12f
            setTextColor(android.graphics.Color.GRAY)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvStatus, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ))

        setContentView(layout)

        // Return 0 since we set content view programmatically
        return 0
    }

    override fun setContentView(layoutResID: Int) {
        if (layoutResID == 0) return // Skip if programmatic layout
        super.setContentView(layoutResID)
    }

    private fun initViews() {
        // Views already initialized in createLoginLayoutProgrammatically
        // If using XML layout, you would do:
        // etUsername = findViewById(R.id.etUsername)
        // etPassword = findViewById(R.id.etPassword)
        // btnLogin = findViewById(R.id.btnLogin)
        // btnBiometric = findViewById(R.id.btnBiometric)
        // tvStatus = findViewById(R.id.tvStatus)
        // tvTitle = findViewById(R.id.tvTitle)
        // tvSubtitle = findViewById(R.id.tvSubtitle)
    }

    private fun setupBiometricButton() {
        when (biometricHelper.isBiometricAvailable()) {
            BiometricHelper.BiometricAvailability.AVAILABLE -> {
                btnBiometric.visibility = android.view.View.VISIBLE
                btnBiometric.setOnClickListener {
                    promptBiometric()
                }
                tvStatus.text = "Fingerprint authentication available"
            }
            BiometricHelper.BiometricAvailability.NOT_ENROLLED -> {
                btnBiometric.visibility = android.view.View.VISIBLE
                btnBiometric.isEnabled = false
                tvStatus.text = "No fingerprints enrolled. Please add one in Settings."
            }
            BiometricHelper.BiometricAvailability.NO_HARDWARE -> {
                btnBiometric.visibility = android.view.View.GONE
                tvStatus.text = "Biometric hardware not available"
            }
            BiometricHelper.BiometricAvailability.HARDWARE_UNAVAILABLE -> {
                btnBiometric.visibility = android.view.View.VISIBLE
                btnBiometric.isEnabled = false
                tvStatus.text = "Biometric hardware temporarily unavailable"
            }
            BiometricHelper.BiometricAvailability.UNKNOWN_ERROR -> {
                btnBiometric.visibility = android.view.View.GONE
                tvStatus.text = "Biometric check returned unknown status"
            }
        }
    }

    private fun setupLoginButton() {
        btnLogin.setOnClickListener {
            val username = etUsername.text.toString().trim()
            val password = etPassword.text.toString().trim()

            if (username.isEmpty() || password.isEmpty()) {
                Toast.makeText(this, "Please enter username and password", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            if (authManager.validateCredentials(username, password)) {
                onLoginSuccess(enableBiometric = true)
            } else {
                Toast.makeText(this, "Invalid credentials. Try user/password123", Toast.LENGTH_LONG).show()
                tvStatus.text = "Login failed. Please try again."
                tvStatus.setTextColor(android.graphics.Color.RED)
            }
        }
    }

    private fun promptBiometricIfAvailable() {
        if (biometricHelper.isBiometricAvailable() == BiometricHelper.BiometricAvailability.AVAILABLE) {
            promptBiometric()
        }
    }

    private fun promptBiometric() {
        biometricHelper.authenticate(
            title = "Fingerprint Login",
            subtitle = "Touch the fingerprint sensor to sign in",
            negativeButtonText = "Use Password Instead",
            onSuccess = {
                onBiometricSuccess()
            },
            onError = { errorCode, errorMessage ->
                onBiometricError(errorCode, errorMessage)
            },
            onFailed = {
                onBiometricFailed()
            }
        )
    }

    private fun onBiometricSuccess() {
        Toast.makeText(this, "Authentication successful!", Toast.LENGTH_SHORT).show()
        tvStatus.text = "Fingerprint verified successfully"
        tvStatus.setTextColor(android.graphics.Color.parseColor("#4CAF50"))
        onLoginSuccess(enableBiometric = true)
    }

    private fun onBiometricError(errorCode: Int, errorMessage: String) {
        when (errorCode) {
            BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                // User chose to use password instead
                tvStatus.text = "Please use your password to sign in"
                tvStatus.setTextColor(android.graphics.Color.GRAY)
                showPasswordFallback()
            }
            BiometricPrompt.ERROR_USER_CANCELED -> {
                tvStatus.text = "Authentication cancelled"
                tvStatus.setTextColor(android.graphics.Color.GRAY)
            }
            BiometricPrompt.ERROR_LOCKOUT -> {
                tvStatus.text = "Too many attempts. Biometric locked. Use password."
                tvStatus.setTextColor(android.graphics.Color.RED)
                showPasswordFallback()
                btnBiometric.isEnabled = false
            }
            BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                tvStatus.text = "Biometric permanently locked. Use password."
                tvStatus.setTextColor(android.graphics.Color.RED)
                showPasswordFallback()
                btnBiometric.isEnabled = false
            }
            else -> {
                tvStatus.text = "Error: $errorMessage"
                tvStatus.setTextColor(android.graphics.Color.RED)
            }
        }
    }

    private fun onBiometricFailed() {
        failedBiometricAttempts++
        tvStatus.text = "Fingerprint not recognized. Try again. ($failedBiometricAttempts/$maxBiometricFailures)"
        tvStatus.setTextColor(android.graphics.Color.parseColor("#FF9800"))

        if (failedBiometricAttempts >= maxBiometricFailures) {
            Toast.makeText(this, "Multiple failed attempts. Please use your password.", Toast.LENGTH_LONG).show()
            showPasswordFallback()
        }
    }

    private fun showPasswordFallback() {
        etUsername.visibility = android.view.View.VISIBLE
        etPassword.visibility = android.view.View.VISIBLE
        btnLogin.visibility = android.view.View.VISIBLE
        etUsername.requestFocus()
    }

    private fun onLoginSuccess(enableBiometric: Boolean) {
        authManager.isAuthenticated = true

        if (enableBiometric && biometricHelper.isBiometricAvailable() == BiometricHelper.BiometricAvailability.AVAILABLE) {
            authManager.isBiometricEnabled = true
        }

        navigateToMain()
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

// ==================== MainActivity ====================
class MainActivity : AppCompatActivity() {

    private lateinit var authManager: AuthManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authManager = AuthManager(this)

        if (!authManager.isAuthenticated) {
            navigateToLogin()
            return
        }

        setupMainScreen()
    }

    private fun setupMainScreen() {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            gravity = android.view.Gravity.CENTER
            setPadding(64, 64, 64, 64)
        }

        val tvWelcome = TextView(this).apply {
            text = "Welcome!"
            textSize = 32f
            setTypeface(null, android.graphics.Typeface.BOLD)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvWelcome, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 16 })

        val tvInfo = TextView(this).apply {
            text = "You are securely logged in.\nBiometric: ${if (authManager.isBiometricEnabled) "Enabled" else "Disabled"}"
            textSize = 16f
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvInfo, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 48 })

        val btnToggleBiometric = Button(this).apply {
            text = if (authManager.isBiometricEnabled) "Disable Biometric Login" else "Enable Biometric Login"
            setOnClickListener {
                authManager.isBiometricEnabled = !authManager.isBiometricEnabled
                text = if (authManager.isBiometricEnabled) "Disable Biometric Login" else "Enable Biometric Login"
                tvInfo.text = "You are securely logged in.\nBiometric: ${if (authManager.isBiometricEnabled) "Enabled" else "Disabled"}"
                Toast.makeText(
                    this@MainActivity,
                    "Biometric login ${if (authManager.isBiometricEnabled) "enabled" else "disabled"}",
                    Toast.LENGTH_SHORT
                ).show()
            }
        }
        layout.addView(btnToggleBiometric, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 24 })

        val btnLogout = Button(this).apply {
            text = "Logout"
            setOnClickListener {
                authManager.logout()
                Toast.makeText(this@MainActivity, "Logged out successfully", Toast.LENGTH_SHORT).show()
                navigateToLogin()
            }
        }
        layout.addView(btnLogout, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ))

        setContentView(layout)
    }

    private fun navigateToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}